const buttonGroupSections: TocSection[] = [
  { id: "explore-behavior", label: "Explore Behavior" },
  { id: "installation", label: "Installation" },
  { id: "examples", label: "Examples" },
  { id: "props", label: "Props" },
  { id: "design-tokens", label: "Design Tokens" },
  { id: "best-practices", label: "Best Practices" },
  { id: "figma-mapping", label: "Figma Mapping" },
  { id: "accessibility", label: "Accessibility" },
  { id: "related", label: "Related Components" },
]

function ButtonGroupExploreBehavior() {
  const [skin, setSkin] = useState("outlined")
  const [size, setSize] = useState("regular")
  const [state, setState] = useState("default")
  const [showLeftIcon, setShowLeftIcon] = useState(false)
  const [showRightIcon, setShowRightIcon] = useState(false)
  const [leftIcon, setLeftIcon] = useState("Mail")
  const [rightIcon, setRightIcon] = useState("ChevronRight")
  // Icon Button tab
  const [ibSkin, setIbSkin] = useState("outlined")
  const [ibSize, setIbSize] = useState("default")  // Figma "Default" matches option value
  const [ibState, setIbState] = useState("default")
  const [ibIcon, setIbIcon] = useState("AlignLeft")

  const LeftIconComp = (lucideIcons as any)[leftIcon]
  const RightIconComp = (lucideIcons as any)[rightIcon]
  const IbIconComp = (lucideIcons as any)[ibIcon]

  const [bgTab, setBgTab] = useState<"button-group" | "icon-button">("button-group")

  const variantMap: Record<string, string> = { outlined: "outline", ghost: "ghost" }
  const sizeMap: Record<string, string> = { large: "lg", regular: "default", small: "sm", default: "default" }
  const isDisabled = state === "disabled" || ibState === "disabled"

  return (
    <div className="rounded-xl border border-border overflow-hidden bg-card">
      {/* ── Tabs ── */}
      <div className="flex border-b border-border">
        {(["button-group", "icon-button"] as const).map(t => (
          <button key={t} onClick={() => setBgTab(t)} className={cn("px-lg py-xs typo-paragraph-sm font-medium transition-colors border-b-2 -mb-px", bgTab === t ? "border-primary text-foreground" : "border-transparent text-muted-foreground hover:text-foreground")}>
            {t === "button-group" ? "Button Group" : "Icon Button"}
          </button>
        ))}
      </div>

        {/* Tab 1: Button Group (784:82792) — 8 properties */}
        {bgTab === "button-group" && (
          <>
            <div className="p-4xl flex items-center justify-center min-h-[200px] bg-muted">
              <ButtonGroup variant={variantMap[skin] as any} size={sizeMap[size] as any}>
                <ButtonGroupItem disabled={isDisabled}>
                  {showLeftIcon && LeftIconComp && <LeftIconComp className="size-4" />}
                  Left
                  {showRightIcon && RightIconComp && <RightIconComp className="size-4" />}
                </ButtonGroupItem>
                <ButtonGroupItem disabled={isDisabled}>
                  {showLeftIcon && LeftIconComp && <LeftIconComp className="size-4" />}
                  Middle
                  {showRightIcon && RightIconComp && <RightIconComp className="size-4" />}
                </ButtonGroupItem>
                <ButtonGroupItem disabled={isDisabled}>
                  {showLeftIcon && LeftIconComp && <LeftIconComp className="size-4" />}
                  Right
                  {showRightIcon && RightIconComp && <RightIconComp className="size-4" />}
                </ButtonGroupItem>
              </ButtonGroup>
            </div>
            <div className="border-t border-border p-lg space-y-md">
              <PropertyTabs label="Skin" value={skin} onChange={setSkin} options={[
                { value: "outlined", label: "Outlined" },
                { value: "ghost", label: "Ghost" },
              ]} />
              <PropertyTabs label="Size" value={size} onChange={setSize} options={[
                { value: "large", label: "Large" },
                { value: "regular", label: "Regular" },
                { value: "small", label: "Small" },
              ]} />
              <PropertyTabs label="State" value={state} onChange={setState} options={[
                { value: "default", label: "Default" },
                { value: "focus", label: "Focus" },
                { value: "hover", label: "Hover" },
                { value: "disabled", label: "Disabled" },
              ]} />
              <div className="flex flex-wrap gap-lg">
                <PropertyToggle label="Show Left Icon" checked={showLeftIcon} onChange={setShowLeftIcon} />
                {showLeftIcon && <div className="space-y-xs max-w-[240px]"><p className="typo-paragraph-xs text-muted-foreground">Left Icon</p><IconPicker value={leftIcon} onChange={setLeftIcon} size="sm" /></div>}
                <PropertyToggle label="Show Right Icon" checked={showRightIcon} onChange={setShowRightIcon} />
                {showRightIcon && <div className="space-y-xs max-w-[240px]"><p className="typo-paragraph-xs text-muted-foreground">Right Icon</p><IconPicker value={rightIcon} onChange={setRightIcon} size="sm" /></div>}
              </div>
            </div>
          </>
        )}

        {/* Tab 2: Button Group Icon Button (784:87178) — 5 properties */}
        {bgTab === "icon-button" && (
          <>
            <div className="p-4xl flex items-center justify-center min-h-[200px] bg-muted">
              <ButtonGroup variant={variantMap[ibSkin] as any} size={sizeMap[ibSize] as any}>
                <ButtonGroupItem size="icon" disabled={ibState === "disabled"} aria-label="Align left">
                  {IbIconComp ? <IbIconComp className="size-4" /> : <AlignLeft className="size-4" />}
                </ButtonGroupItem>
                <ButtonGroupItem size="icon" disabled={ibState === "disabled"} aria-label="Align center">
                  <AlignCenter className="size-4" />
                </ButtonGroupItem>
                <ButtonGroupItem size="icon" disabled={ibState === "disabled"} aria-label="Align right">
                  <AlignRight className="size-4" />
                </ButtonGroupItem>
              </ButtonGroup>
            </div>
            <div className="border-t border-border p-lg space-y-md">
              <PropertyTabs label="Skin" value={ibSkin} onChange={setIbSkin} options={[
                { value: "outlined", label: "Outlined" },
                { value: "ghost", label: "Ghost" },
              ]} />
              <PropertyTabs label="Size" value={ibSize} onChange={setIbSize} options={[
                { value: "large", label: "Large" },
                { value: "default", label: "Default" },
                { value: "small", label: "Small" },
              ]} />
              <PropertyTabs label="State" value={ibState} onChange={setIbState} options={[
                { value: "default", label: "Default" },
                { value: "focus", label: "Focus" },
                { value: "hover", label: "Hover" },
                { value: "disabled", label: "Disabled" },
              ]} />
              <div className="space-y-xs max-w-[240px]">
                <p className="typo-paragraph-xs text-muted-foreground">Icon</p>
                <IconPicker value={ibIcon} onChange={setIbIcon} size="sm" />
              </div>
            </div>
          </>
        )}
    </div>
  )
}

