function SelectPropsTable() {
  const props = [
    {
      name: "Select (Root)",
      type: "",
      default: "",
      description: "",
    },
    {
      name: "value",
      type: "string",
      default: "—",
      description: "The controlled value of the select.",
    },
    {
      name: "defaultValue",
      type: "string",
      default: "—",
      description: "The default value for uncontrolled usage.",
    },
    {
      name: "onValueChange",
      type: "(value: string) => void",
      default: "—",
      description: "Callback when the selected value changes.",
    },
    {
      name: "disabled",
      type: "boolean",
      default: "false",
      description: "Disables the entire select.",
    },
    {
      name: "open / onOpenChange",
      type: "boolean / (open: boolean) => void",
      default: "—",
      description: "Controlled open state of the dropdown.",
    },
    {
      name: "SelectTrigger",
      type: "",
      default: "",
      description: "",
    },
    {
      name: "size",
      type: '"lg" | "default" | "sm" | "xs"',
      default: '"default"',
      description: "The size of the trigger. Matches Input sizes.",
    },
    {
      name: "aria-invalid",
      type: "boolean",
      default: "false",
      description: "Marks the trigger as invalid with error styling.",
    },
    {
      name: "SelectItem",
      type: "",
      default: "",
      description: "",
    },
    {
      name: "value (item)",
      type: "string",
      default: "required",
      description: "The value submitted when this item is selected.",
    },
    {
      name: "disabled (item)",
      type: "boolean",
      default: "false",
      description: "Prevents this item from being selected.",
    },
  ]

  return (
    <div className="overflow-x-auto rounded-xl border border-border bg-card">
      <table className="w-full text-xs">
        <thead>
          <tr className="bg-muted border-b border-border text-left">
            <th className="px-md py-sm font-semibold">Prop</th>
            <th className="px-md py-sm font-semibold">Type</th>
            <th className="px-md py-sm font-semibold">Default</th>
            <th className="px-md py-sm font-semibold">Description</th>
          </tr>
        </thead>
        <tbody>
          {props.map((p) =>
            p.type === "" ? (
              <tr key={p.name} className="border-b border-border bg-muted">
                <td className="px-4 py-2 font-mono text-xs font-bold text-foreground" colSpan={4}>
                  {p.name}
                </td>
              </tr>
            ) : (
              <tr key={p.name} className="border-b border-border last:border-0">
                <td className="px-md py-sm font-mono text-primary font-semibold whitespace-nowrap">
                  {p.name}
                </td>
                <td className="px-md py-sm font-mono text-muted-foreground max-w-xs">
                  {p.type}
                </td>
                <td className="px-md py-sm font-mono">{p.default}</td>
                <td className="px-md py-sm text-muted-foreground">
                  {p.description}
                </td>
              </tr>
            )
          )}
        </tbody>
      </table>
    </div>
  )
}

