function ChipExploreBehavior() {
  const [chipState, setChipState] = useState<"Default" | "Hover" | "Selected">("Default")
  const [chipSize, setChipSize] = useState<"md" | "sm">("md")
  const [chipStyle, setChipStyle] = useState<"Default" | "Closable" | "Icon prefix" | "Icon prefix - Closable">("Default")

  const hasIcon = chipStyle.includes("Icon prefix")
  const isClosable = chipStyle.includes("Closable")
  const isSelected = chipState === "Selected"
  const isHover = chipState === "Hover"

  return (
    <div className="rounded-xl border border-border overflow-hidden bg-card">
      <div className="p-4xl flex items-center justify-center min-h-[160px] bg-card-subtle">
        <div className={isHover ? "[&_[data-slot=chip]]:bg-accent [&_[data-slot=chip]]:text-foreground" : ""}>
          <Chip
            size={chipSize}
            selected={isSelected}
            icon={hasIcon ? <Search /> : undefined}
            closable={isClosable}
            onClose={() => {}}
          >
            Chip name
          </Chip>
        </div>
      </div>
      <div className="border-t border-border p-lg space-y-md">
        <PropertyTabs label="State" value={chipState} onChange={(v) => setChipState(v as any)} options={[
          { value: "Default", label: "Default" },
          { value: "Hover", label: "Hover" },
          { value: "Selected", label: "Selected" },
        ]} />
        <PropertyTabs label="Size" value={chipSize} onChange={(v) => setChipSize(v as any)} options={[
          { value: "md", label: "md (32px)" },
          { value: "sm", label: "sm (24px)" },
        ]} />
        <PropertyTabs label="Style" value={chipStyle} onChange={(v) => setChipStyle(v as any)} options={[
          { value: "Default", label: "Default" },
          { value: "Closable", label: "Closable" },
          { value: "Icon prefix", label: "Icon prefix" },
          { value: "Icon prefix - Closable", label: "Icon prefix - Closable" },
        ]} />
      </div>
    </div>
  )
}

