function AlertExploreBehavior() {
  const [type, setType] = useState("default")
  const [icon, setIcon] = useState("")
  /* Figma: only Neutral type allows icon swap; others use fixed icon */
  const handleTypeChange = (v: string) => { setType(v); if (v !== "default") setIcon("") }
  const [showIcon, setShowIcon] = useState(true)
  const [showTitle, setShowTitle] = useState(true)
  const [showSubtitle, setShowSubtitle] = useState(true)
  const [dismissable, setDismissable] = useState(false)
  const [inCard, setInCard] = useState(false)
  const [showAction, setShowAction] = useState(false)
  const [showSecondaryAction, setShowSecondaryAction] = useState(false)
  /* Figma constraint: Secondary Action only available when Show Action is on */
  const handleShowActionChange = (v: boolean) => { setShowAction(v); if (!v) setShowSecondaryAction(false) }

  /* Figma default icon per type */
  const defaultIconName: Record<string, string> = {
    default: "Info",
    destructive: "CircleAlert",
    success: "CircleCheck",
    warning: "TriangleAlert",
    emphasis: "Info",
  }
  const activeIconName = icon || defaultIconName[type] || "Info"
  const ActiveIconComp = allLucideIcons.find((i) => i.name === activeIconName)?.icon
  // activeIcon removed — now using icon prop on Alert directly

  const titles: Record<string, string> = {
    default: "Heads up!",
    destructive: "Error",
    success: "Success",
    warning: "Warning",
    emphasis: "Information",
  }
  const descs: Record<string, string> = {
    default: "You can add components using the CLI.",
    destructive: "Your session has expired. Please log in again.",
    success: "Your changes have been saved successfully.",
    warning: "Your trial expires in 3 days. Upgrade to continue.",
    emphasis: "A new version is available. Update to get the latest features.",
  }

  /* Figma In Card spec handled by Alert inCard prop:
     - border-transparent, py-xs px-sm, neutral: bg-card-subtle */

  const alertContent = (
    <>
      {showTitle && <AlertTitle>{titles[type]}</AlertTitle>}
      {showSubtitle && <AlertDescription>{descs[type]}</AlertDescription>}
      {showAction && (
        <AlertAction
          actionLabel="Action"
          secondaryLabel={showSecondaryAction ? "Cancel" : undefined}
          actionVariant={type === "destructive" ? "destructive" : "secondary"}
        />
      )}
      {dismissable && <AlertDismiss />}
    </>
  )

  return (
    <div className="rounded-xl border border-border overflow-hidden bg-card">
      <div className="p-4xl flex items-center justify-center min-h-[160px] bg-card-subtle">
        <div className="w-full max-w-lg">
          <Alert variant={type as "default" | "destructive" | "success" | "warning" | "emphasis"} inCard={inCard} icon={showIcon ? ActiveIconComp || Info : undefined}>
            {alertContent}
          </Alert>
        </div>
      </div>
      <div className="border-t border-border p-lg space-y-md">
        <PropertyTabs label="Type" value={type} onChange={handleTypeChange} options={[
          { value: "default", label: "Neutral" },
          { value: "destructive", label: "Error" },
          { value: "success", label: "Success" },
          { value: "warning", label: "Warning" },
          { value: "emphasis", label: "Emphasis" },
        ]} />
        <div className="space-y-xs max-w-[240px]">
          <p className={cn("typo-paragraph-xs text-muted-foreground", type !== "default" && "opacity-50")}>Icon</p>
          <IconPicker value={activeIconName} onChange={setIcon} disabled={type !== "default"} size="sm" />
        </div>
        <div className="flex flex-wrap gap-lg">
          <PropertyToggle label="Dismissable" checked={dismissable} onChange={setDismissable} />
          <PropertyToggle label="In Card" checked={inCard} onChange={setInCard} />
          <PropertyToggle label="Show Title" checked={showTitle} onChange={(v) => { setShowTitle(v); if (!v && !showSubtitle) setShowSubtitle(true) }} />
          <PropertyToggle label="Show Subtitle" checked={showSubtitle} onChange={(v) => { setShowSubtitle(v); if (!v && !showTitle) setShowTitle(true) }} />
          <PropertyToggle label="Show Icon" checked={showIcon} onChange={setShowIcon} />
          <PropertyToggle label="Show Action" checked={showAction} onChange={handleShowActionChange} />
          <PropertyToggle label="Show Secondary Action" checked={showSecondaryAction} onChange={setShowSecondaryAction} />
        </div>
      </div>
    </div>
  )
}

