function AccordionPropsTable() {
  const renderTable = (title: string, props: { name: string; type: string; default: string; description: string }[]) => (
    <div className="space-y-2">
      <h3 className="font-body font-semibold text-sm">{title}</h3>
      <div className="overflow-x-auto rounded-xl border border-border bg-card">
        <table className="w-full text-xs">
          <thead>
            <tr className="bg-muted border-b border-border text-left">
              <th className="px-md py-sm font-semibold">Prop</th>
              <th className="px-md py-sm font-semibold">Type</th>
              <th className="px-md py-sm font-semibold">Default</th>
              <th className="px-md py-sm font-semibold">Description</th>
            </tr>
          </thead>
          <tbody>
            {props.map((p) => (
              <tr key={p.name} className="border-b border-border last:border-0">
                <td className="px-md py-sm font-mono text-primary font-semibold whitespace-nowrap">{p.name}</td>
                <td className="px-md py-sm font-mono text-muted-foreground max-w-xs">{p.type}</td>
                <td className="px-md py-sm font-mono">{p.default}</td>
                <td className="px-md py-sm text-muted-foreground">{p.description}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  )

  return (
    <div className="space-y-4">
      {renderTable("Accordion", [
        { name: "type", type: '"single" | "multiple"', default: "—", description: "Whether one or multiple items can be open at once." },
        { name: "collapsible", type: "boolean", default: "false", description: 'When type="single", allows closing the open item by clicking its trigger.' },
        { name: "defaultValue", type: "string | string[]", default: "—", description: "The value(s) of the item(s) open by default (uncontrolled)." },
        { name: "value", type: "string | string[]", default: "—", description: "The controlled value(s) of the open item(s)." },
        { name: "onValueChange", type: "(value) => void", default: "—", description: "Callback when the open item(s) change." },
        { name: "disabled", type: "boolean", default: "false", description: "Disables all items in the accordion." },
        { name: "className", type: "string", default: "—", description: "Additional CSS classes for the root element." },
      ])}
      {renderTable("AccordionItem", [
        { name: "value", type: "string", default: "—", description: "Unique identifier for the item (required)." },
        { name: "disabled", type: "boolean", default: "false", description: "Disables this specific item." },
        { name: "className", type: "string", default: "—", description: "Additional CSS classes." },
      ])}
      {renderTable("AccordionTrigger", [
        { name: "children", type: "React.ReactNode", default: "—", description: "Trigger label content." },
        { name: "className", type: "string", default: "—", description: "Additional CSS classes." },
      ])}
      {renderTable("AccordionContent", [
        { name: "children", type: "React.ReactNode", default: "—", description: "Content shown when the item is open." },
        { name: "className", type: "string", default: "—", description: "Additional CSS classes for the inner wrapper." },
      ])}
    </div>
  )
}

function AccordionTokensTable() {
  return <DesignTokensTable tokens={[
    { token: "text-foreground", cssVar: "--foreground", value: "#252522", label: "foreground", usage: "Trigger label & content text" },
    { token: "text-muted-foreground", cssVar: "--muted-foreground", value: "#6f6f6a", label: "muted-fg", usage: "Chevron icon color" },
    { token: "border-border", cssVar: "--border", value: "#e9e9e7", label: "border", usage: "Item bottom border" },
    { token: "ring-ring", cssVar: "--ring", value: "#e9e9e7", label: "ring", usage: "Focus ring (3px)" },
    { token: "rounded-lg", cssVar: "--radius-lg", value: "8px", usage: "Focus state border-radius" },
    { token: "gap-xs", cssVar: "--spacing-xs", value: "8px", usage: "Trigger gap (label ↔ icon)" },
    { token: "py-sm", cssVar: "--spacing-sm", value: "12px", usage: "Trigger vertical padding, content bottom" },
    { token: "size-md", cssVar: "--spacing-md", value: "16px", usage: "Chevron icon size" },
  ]} />
}

/**
 * Explore Behavior — static variant preview matching Figma component 100%:
 *   State:    Default | Hover | Focus | Disable
 *   Type:     Open | Closed
 *   End Item: False | True
 *
 * Uses real Accordion component but with pointer-events-none to prevent
 * interactive states (hover/focus/click) from overriding the controlled preview.
 * Native hover:underline and focus-visible:ring are neutralized via CSS overrides.
 */
function AccordionExploreBehavior() {
  const [activeTab, setActiveTab] = useState<"trigger" | "content">("trigger")

  // Accordion Trigger controls
  const [state, setState] = useState("Default")
  const [type, setType] = useState("Closed")
  const [endItem, setEndItem] = useState(false)

  const isDisable = state === "Disable"
  const isHover = state === "Hover"
  const isFocus = state === "Focus"
  const effectiveValue = isDisable ? undefined : type === "Open" ? "preview" : undefined

  return (
    <div className="rounded-xl border border-border overflow-hidden bg-card">
      {/* ── Tabs ── */}
      <div className="flex border-b border-border">
        {(["trigger", "content"] as const).map(t => (
          <button key={t} onClick={() => setActiveTab(t)} className={cn("px-lg py-xs typo-paragraph-sm font-medium transition-colors border-b-2 -mb-px", activeTab === t ? "border-primary text-foreground" : "border-transparent text-muted-foreground hover:text-foreground")}>
            {t === "trigger" ? "Accordion Trigger" : "Accordion Content"}
          </button>
        ))}
      </div>

      {/* ---- Tab: Accordion Trigger ---- */}
      {activeTab === "trigger" && (
        <>
          <div className="p-4xl flex items-center justify-center min-h-[200px] bg-card-subtle">
            <div className={[
              "w-full max-w-md pointer-events-none",
              "[&_[data-slot=accordion-trigger]]:hover:no-underline",
              isHover ? "[&_[data-slot=accordion-trigger]]:underline [&_[data-slot=accordion-trigger]]:rounded-lg" : "",
              isFocus ? "[&_[data-slot=accordion-trigger]]:rounded-lg [&_[data-slot=accordion-trigger]]:shadow-[0_0_0_3px_var(--ring)]" : "",
              endItem ? "" : "[&_[data-slot=accordion-item]]:!border-b",
            ].filter(Boolean).join(" ")}>
              <Accordion
                type="single"
                collapsible
                value={effectiveValue}
                disabled={isDisable}
              >
                <AccordionItem
                  value="preview"
                  className={endItem ? "last:border-b-0" : ""}
                >
                  <AccordionTrigger>Label</AccordionTrigger>
                  <AccordionContent>
                    We offer standard (5-7 days), express (2-3 days), and overnight shipping. Free shipping on international orders.
                  </AccordionContent>
                </AccordionItem>
              </Accordion>
            </div>
          </div>
          <div className="border-t border-border p-lg space-y-md">
            <PropertyTabs label="State" value={state} onChange={setState} options={[["Default","Default"],["Hover","Hover"],["Focus","Focus"],["Disable","Disable"]]} />
            <PropertyTabs label="Type" value={isDisable ? "Closed" : type} onChange={(v) => { if (!isDisable) setType(v) }} options={[["Open","Open"],["Closed","Closed"]]} />
            <PropertyToggle label="End Item" checked={endItem} onChange={setEndItem} />
          </div>
        </>
      )}

      {/* ---- Tab: Accordion Content ---- */}
      {activeTab === "content" && (
        <>
          <div className="p-4xl flex items-center justify-center min-h-[200px] bg-card-subtle">
            <div className="w-full max-w-md">
              <p className="typo-paragraph-sm text-foreground">
                This is the content shown when opening an accordion.
              </p>
            </div>
          </div>
          <div className="border-t border-border p-lg space-y-md">
            <PropertyTabs label="Property 1" value="Default" onChange={() => {}} options={[["Default","Default"]]} />
          </div>
        </>
      )}
    </div>
  )
}

